function duckVariant(variantId) {
  return window.PsyduckData.DUCK_VARIANTS.find((v) => v.id === variantId) || window.PsyduckData.DUCK_VARIANTS[0];
}

// Um patinho da fazenda, do tamanho de um ícone — usado no cenário do
// lago e em qualquer lista/miniatura.
function renderDuckIcon(variantId, { size = 72 } = {}) {
  const v = duckVariant(variantId);
  const markup = duckBodyMarkup({
    bodyColor: v.bodyColor,
    bellyColor: v.bellyColor,
    beakColor: v.beakColor,
    face: FACE_BY_MOOD.content,
    accessory: v.accessory,
  });
  return `<svg viewBox="0 0 512 320" width="${size}" height="${size * 0.625}" class="duck-icon duck-${v.id}" role="img" aria-label="${v.label}">${markup}</svg>`;
}

// Uma vitória-régia (lily pad) — folha verde + florzinha, repetida no
// lago em posições fixas.
function lilyPad(cx, cy, scale = 1) {
  const s = 16 * scale;
  return `
    <rect x="${cx - s}" y="${cy - s * 0.6}" width="${s * 2}" height="${s * 1.2}" fill="var(--scene-lily)"/>
    <rect x="${cx - s * 0.3}" y="${cy - s * 0.9}" width="${s * 0.6}" height="${s * 0.6}" fill="var(--scene-lily-flower)"/>
  `;
}

// Pinheiro pixelado — tronco + 3 blocos verdes decrescentes (silhueta
// de escada, sem curva nenhuma).
function pineTree(x, y, scale = 1) {
  const w = 60 * scale;
  return `
    <rect x="${x + w * 0.42}" y="${y + w * 1.35}" width="${w * 0.16}" height="${w * 0.3}" fill="var(--scene-trunk)"/>
    <rect x="${x}" y="${y + w * 0.9}" width="${w}" height="${w * 0.45}" fill="var(--scene-pine)"/>
    <rect x="${x + w * 0.13}" y="${y + w * 0.45}" width="${w * 0.74}" height="${w * 0.45}" fill="var(--scene-pine)"/>
    <rect x="${x + w * 0.26}" y="${y}" width="${w * 0.48}" height="${w * 0.45}" fill="var(--scene-pine)"/>
  `;
}

// Árvore pequena e redonda (folhagem em bloco quadrado) perto da casa.
function roundTree(x, y, scale = 1) {
  const w = 46 * scale;
  return `
    <rect x="${x + w * 0.4}" y="${y + w * 0.7}" width="${w * 0.2}" height="${w * 0.5}" fill="var(--scene-trunk)"/>
    <rect x="${x}" y="${y}" width="${w}" height="${w * 0.75}" fill="var(--scene-round-leaf)"/>
  `;
}

// Casa pequena (canto esquerdo, sobre a grama do cenário novo).
function smallHouse(x, y) {
  return `
    <rect x="${x}" y="${y + 20}" width="80" height="55" fill="var(--scene-barn)"/>
    <rect x="${x - 6}" y="${y}" width="92" height="10" fill="var(--scene-barn-roof)"/>
    <rect x="${x + 6}" y="${y + 10}" width="70" height="10" fill="var(--scene-barn-roof)"/>
    <rect x="${x + 34}" y="${y + 45}" width="18" height="30" fill="var(--scene-barn-door)"/>
    <rect x="${x + 10}" y="${y + 32}" width="16" height="16" fill="var(--scene-window)"/>
  `;
}

// Horta compacta + vaso, ao lado da casa.
function smallGarden(x, y) {
  return `
    <rect x="${x}" y="${y}" width="52" height="20" fill="var(--scene-soil-frame)"/>
    <rect x="${x + 3}" y="${y + 3}" width="46" height="14" fill="var(--scene-soil)"/>
    <rect x="${x + 6}" y="${y - 8}" width="4" height="10" fill="var(--scene-round-leaf)"/>
    <rect x="${x + 18}" y="${y - 10}" width="4" height="12" fill="var(--scene-round-leaf)"/>
    <rect x="${x + 32}" y="${y - 8}" width="4" height="10" fill="var(--scene-round-leaf)"/>
    <rect x="${x + 44}" y="${y - 9}" width="4" height="11" fill="var(--scene-round-leaf)"/>
    <rect x="${x - 16}" y="${y + 4}" width="12" height="12" fill="var(--scene-pot)"/>
    <rect x="${x - 13}" y="${y - 3}" width="6" height="7" fill="var(--scene-round-leaf)"/>
  `;
}

// Cachorro pequeno, andando perto da horta.
function smallDog(x, y) {
  return `
    <rect x="${x}" y="${y}" width="20" height="11" fill="var(--scene-dog)"/>
    <rect x="${x + 16}" y="${y - 5}" width="9" height="9" fill="var(--scene-dog)"/>
    <rect x="${x - 2}" y="${y + 9}" width="4" height="6" fill="var(--scene-dog)"/>
    <rect x="${x + 16}" y="${y + 9}" width="4" height="6" fill="var(--scene-dog-dark)"/>
  `;
}

// Lago pequeno (oval — única curva permitida, água de verdade não tem
// canto reto) com 3 vitórias-régias, do lado direito da cena.
function smallLake(cx, cy) {
  const lilies = [
    [cx - 26, cy - 4, 0.6], [cx + 8, cy + 6, 0.5], [cx + 24, cy - 6, 0.55],
  ]
    .map(([lx, ly, s]) => lilyPad(lx, ly, s))
    .join("");
  return `
    <ellipse cx="${cx}" cy="${cy}" rx="46" ry="17" fill="var(--scene-lake-edge)"/>
    <ellipse cx="${cx}" cy="${cy + 2}" rx="41" ry="13" fill="var(--scene-lake)"/>
    ${lilies}
  `;
}

// Cena de fundo — céu com ciclo dia/noite/pôr-do-sol/nascer, clima real
// (chuva/neve/tempestade/limpo), montanhas e uma cidadezinha ao fundo
// (arte fornecida pelo usuário, ver cenario_pixel_art_16bit-v2.html).
// A casa/horta/cachorro/lago do Psyduck entram por cima, nesta função,
// pra completar com a identidade de "fazenda" do app. As classes de
// tema/clima (`theme-*`/`weather-active-*`) são aplicadas de fora
// (app.js → updateSceneThemeClasses), não aqui — a função só desenha a
